var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"취향과 다르게 아기자기한 곳에 머물고 계셨네요, 세라펠.","JPN":"好みとは違って可愛らしいところに住んでいるんですね、セラフェル。","ENG":"What a cute and cozy place you're staying at, Serapel. It doesn't really suit you, right?","TWN":"跟你的喜好不同，你住的地方很可愛呢，塞拉費爾。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그렇지. 주인이 없을 때는 이런 곳에라도 머물러야 마음이 진정돼.","JPN":"そうね。マスターがいない時にはこんなところにでもいないと心が落ち着かないの。","ENG":"Yes. When my master isn't around, staying in a place like this helps to calm my nerves.","TWN":"是啊。主人不在的時候，至少要待在這樣的地方，我的心才會平靜。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아, 흥분돼서 당장이라도 확인하고 싶구나.","JPN":"ああ、興奮してしまって、今すぐにでも確認したくてたまらないわ。","ENG":"Ahh... I'm so aroused I want to check right away.","TWN":"啊啊，我太激動了，好想馬上就確認啊。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"그 아이가……. 메이의 핏줄이 내게 다시 한 번 타오르는 고통을 느끼게 해 줄 수 있을지.","JPN":"あの子が……メイの血筋が私にもう一度燃え上げるような苦痛を味わわせてくれるかどうか。","ENG":"That child... I want to see if May's bloodline will gift me that burning pain once more.","TWN":"那孩子……梅伊的血脈究竟能否讓我再次感受到燃燒的痛苦。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"너무 걱정 마세요. 늑대의 송곳니가 기다리고 있을 테니까요.","JPN":"そう心配することはありません。狼の牙が待っているはずですから。","ENG":"Don't worry so much. The Wolf's fang will be waiting for you.","TWN":"別太擔心了。狼牙應該在等著你呢。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"후후, 쉽게 넘길 생각도 없으면서 말만큼은 여전히 달콤하구나.","JPN":"ふふ、簡単に渡すつもりもないくせに、言葉だけは相変わらずうまいのね。","ENG":"Fu fu. Your hollow words are like honey, even though I know you don't want to give her up so easily.","TWN":"呵呵，你明明不會輕易讓給我，卻還說得這麼好聽。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"하지만 정말로 왔군. 속삭이는 자의 사도에게 전해 들었을 때는 믿지 않았건만.","JPN":"それにしても、本当に来るとはね。囁く者の使徒から聞いた時には信じていなかったけど。","ENG":"Anyway, you did come to me. I didn't believe what the Apostle of the Whisperer told though.","TWN":"不過你真的來了啊。低語者的使徒告訴我時我還不相信。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"네 애완동물 건은 미안하게 됐다. 오랜만에 깨어난 나머지 조금 과하게 사용했던가.","JPN":"あなたのペットの件は悪かったわ。久々に目覚めたせいか、少し力を使いすぎてしまったみたい。","ENG":"I'm sorry about what happened to your pet. Did I overuse it after I awoke from a long slumber?","TWN":"你的寵物那件事，真對不起了。因為太久沒有醒來，我好像有點使用過度了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"확실히 나쁘진 않았어. 그토록 강한 생기를 지닌 자는 어떻게 찾았지?","JPN":"確かに悪くはなかったわ。あれほど強い生気を持った人間をどうやって探し出したの？","ENG":"It wasn't bad at all. How did you come across someone with such vigor?","TWN":"不過確實很不錯。那麼充滿活力的人，你是怎麼找到的？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"……잠시 협력하는 사이에게 거기까지 답변해 드릴 이유는 없을 것 같네요.","JPN":"……一時的に協力する間柄で、そこまで答えなければならない理由はないと思います。","ENG":"...We don't see why we have to answer you when our brief partnership is coming to an end.","TWN":"……大家只是暫時合作的關係，我們好像沒理由回答你的問題。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"질문의 의도가 저희를 자극해서 고통 받기 위해서라는 점 때문에, 더더욱.","JPN":"質問の意図が我々を刺激して苦痛を受けようとするためなら、なおさら。","ENG":"Also, because your intention is to use our response to feel pain.","TWN":"而且如果你提問的意圖是刺激我們讓我們痛苦，那我們就更沒必要回答了。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"후훗. 떨어져 나온 단말 주제에 영리한 척 굴긴.","JPN":"ふふっ。遠隔端末風情がずいぶんお利巧なことを言うのね。","ENG":"Hah hah. A mere piece trying to be clever, I see.","TWN":"呵呵，只是一個分身而已，裝什麼聰明。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그래서, 새로운 <color=#ffd34c>주인</color>은 어디에 있나요?","JPN":"ところで、新しい<color=#ffd34c>マスター</color>はどこにいるのですか？","ENG":"So? Where is your new <color=#ffd34c>master</color>?","TWN":"所以，新<color=#ffd34c>主人</color>在哪裡？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"잠시 협력하는 사이에게 거기까지 답변해 줘야 하던가?","JPN":"一時的に協力する間柄で、そこまで答える必要があるのかしら。","ENG":"I don't need to answer you too, do I?","TWN":"大家只是暫時合作的關係，我有必要回答你的問題嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"그렇네요. 이번에는 한 입에 삼켜지지 않길 바랄게요.","JPN":"それもそうですね。今度はひと口にのみ込まれないといいですね。","ENG":"Fair enough. We hope she doesn't get swallowed in one bite this time.","TWN":"是啊。希望這次不會被我們一口吞掉。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"아. 잠시만요.","JPN":"あ、少々お待ちを。","ENG":"Oh, one moment, please.","TWN":"啊，等一下。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네, 교수님. 말씀하세요.","JPN":"はい、教授。どうぞ。","ENG":"Yes, Professor?","TWN":"喂，教授，你請說。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"집중하고 계셨군요. 위험한 곳에 가셨나 봅니다.","JPN":"集中しておられたのですね。危険なところにいらっしゃったのですか。","ENG":"I see you were concentrating. Are you somewhere dangerous?","TWN":"你看起來很專注，是去了很危險的地方嗎。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮아요. <color=#ffd34c>저희</color>는 하나지만 여럿이니까요.","JPN":"大丈夫です。<color=#ffd34c>我々</color>は一つであり複数ですから。","ENG":"We're all right. <color=#ffd34c>We</color> are one, but also many.","TWN":"沒關係。因為<color=#ffd34c>我們</color>既是一個整體，也是許多個體。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그보다 개인적인 용무를 해결하러 간다고 하지 않으셨나요? 무슨 일이시죠?","JPN":"それより、個人的な用事を解決しに行くとおっしゃいませんでしたか？　何かありましたか？","ENG":"Anyway, didn't you say you were taking care of personal matters? Is something wrong?","TWN":"對了，你不是說要去辦私事嗎？是什麼事？"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"맥크레디 양이 사라졌습니다. 시설에서 원인 불명의 사고가 일어난 모양이더군요.","JPN":"マクレディーさんが消えました。施設で原因不明の事故が起きたようです。","ENG":"Ms. MacCready has gone missing. An unexpected accident occurred at the facility.","TWN":"麥克蕾蒂不見了。設施裡好像發生了不明原因的事故。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회와 연이 있는 경찰 고위직을 통해 조사를 부탁한 상황입니다.","JPN":"学会とつながりがある警察上部を通じて捜査を依頼しました。","ENG":"I have asked a police official who has ties to the Society to investigate.","TWN":"我已經拜託和學會關係不錯的員警高層調查了。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래요. 레지나 님이…….","JPN":"そうですか。レジーナ様が……","ENG":"I see. Miss Regina is…","TWN":"是嗎，蕾佳娜……"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"어떻게 하시겠습니까? 개인적으로는 무척 흥미로운 상황인지라…….","JPN":"どうなさいますか？　個人的にはとても興味深い状況ですので……","ENG":"What are your future plans? Personally, I find it an intriguing situation...","TWN":"你想怎麼辦？我個人覺得這種情況非常有趣……"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"괜찮아요. 레지나 님은 분명 제때 돌아오실 테니까.","JPN":"大丈夫です。レジーナ様はきっと必要な時にお戻りになりますから。","ENG":"It's all right. She will certainly return in time.","TWN":"沒關係，蕾佳娜到時候一定會回來的。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"요양이 아주 조금 더 길어질 뿐이랍니다. ","JPN":"療養がほんの少し長引くだけです。 ","ENG":"However, her recuperation might take longer than expected. ","TWN":"只是休養時間會延長一點而已。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"흠. 알겠습니다. 그렇게 말씀하신다면야.","JPN":"ふむ。わかりました。そうおっしゃるのなら。","ENG":"Hmm... If you say so, I understand.","TWN":"嗯，我知道了。既然你這麼說。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"생물학부가 악단과 접촉했다더군요. 곧 합류할 겁니다.","JPN":"生物学部が楽団と接触したそうです。もうすぐ合流するでしょう。","ENG":"The Biology Department has made contact with the Orchestra. They will be joining you soon.","TWN":"生物學院和樂團接觸了。她們應該很快就會加入。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"방해꾼들이 달라붙어서 걱정했는데 다행이네요. 좋은 소식 고마워요.","JPN":"邪魔者がくっついているので心配していましたが、安心しました。いい知らせ、ありがとうございます。","ENG":"What good news. We were worried about hecklers getting on our back.","TWN":"那正好，我們本來還擔心會有人來礙事。謝謝你告訴我們這個好消息。"},"stage":{"bg":"CAR","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"외출하는 데 단장하려면 시간이 얼마나 걸릴까요, 세라펠?","JPN":"出かけるための支度にどれだけかかりますか？　セラフェル。","ENG":"How long will it take for you to get dressed, Serapel?","TWN":"想打扮一下出門的話需要多長時間，塞拉費爾？"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"글쎄. 속삭이는 자가 언제 클리포트 게임을 선포하느냐에 따라 달렸지.","JPN":"そうね。囁く者がいつクリフォトゲームを宣布するかによるわ。","ENG":"Hmm... Depends on when the Whisperer declares the start of the Qliphoth Game.","TWN":"這個嘛，取決於低語者什麼時候宣佈逆卡巴拉遊戲開始。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아아, 기대되는 순간이군. 오랜만에 아주…….","JPN":"ああ、その瞬間が楽しみだわ。久々にとても……","ENG":"Aah... I've been eagerly awaiting this moment for so long...","TWN":"啊啊，好期待那一刻啊，應該可以體驗……"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SERAPEL_QLIPHOTH_NULL_NULL","text":{"KOREA":"아주 고통스러운 시간이 되겠어.","JPN":"とても苦しい時間になりそう。","ENG":"It will be a time of great suffering.","TWN":"久違的痛苦吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"마침 주유소가 있군. 여기서 잠시 쉬어가지.","JPN":"ちょうどガソリンスタンドがあるな。ここでしばらく休憩しよう。","ENG":"There is a gas station ahead. Let's take a break there.","TWN":"正好有個加油站，在這裡休息一下吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"다들 내려, 아가씨들. 갈길이 머니 얼른 볼일 보러 갔다 오라고.","JPN":"下りてくれ、お嬢ちゃんたち。先は長いんだ、急いで用を足して帰ってきてくれ。","ENG":"Get out, ladies. We have a long road ahead of us, so go get your business done quick.","TWN":"快下車，小姐們。路途遙遠，都快去方便一下吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DRIVER_NPC_ALPHA_NULL","text":{"KOREA":"이런 허허벌판 한가운데에서 가 봤자 어디로 가겠냐마는. 흐흐흐…….","JPN":"こんな荒野のど真ん中じゃ、行くっていってもどこにも行くところはないだろうけどな。ふふふ……","ENG":"But then again, where can you ladies go in the middle of nowhere... Kekeke...","TWN":"就是不知道在這種空曠的原野中能去哪裡，呵呵呵……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"말 없이 움직이는 마차를 직접 타 보다니……. 꿈만 같아요.","JPN":"馬なしで走る馬車に乗ることになるなんて……夢みたいです。","ENG":"It's my first time riding a carriage without a horse... It's like I'm in a dream...!","TWN":"我竟然坐上了沒有馬也能跑的馬車……好像做夢一樣。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으으, 트럭 짐칸은 사람 탈 곳이 못 되네요. 이러다 엉덩이가 쪼개지겠어요.","JPN":"うう、トラックの荷台は人が乗るところではありませんね。このままではお尻が割れてしまいますわ。","ENG":"Ngh... The truck bed is no place for passengers. I feel I might bruise my buttocks!","TWN":"呃呃，卡車的車廂真不是人待的地方。我的屁股好痛。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"앗, 그런 문제는 제게 맡겨 주세요.","JPN":"あっ、それでしたらお任せください。","ENG":"Oh! If you're feeling uncomfortable, leave it to me.","TWN":"啊，這個問題交給我吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"제가 엎드려서 부학회장님의 방석이라도 되어 드릴게요. 간병인이니까요.","JPN":"私が伏せて副学会長様のクッションにでもなります。看病人ですから。","ENG":"I'll lie down and become your cushion. I am your caregiver after all.","TWN":"我可以躺下給副學會長當坐墊，因為我是你的看護。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 아뇨. 그러지 말아 주세요. 제가 더 부담스럽습니다.","JPN":"い、いいえ。それはやめてください。かえって落ち着きませんわ。","ENG":"N-no, thank you. That won't be necessary.","TWN":"不…不用，千萬別那麼做。那樣我會有壓力的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 얄궂은 상황이군. 맥크레디 집안 사람이 트럭 짐칸을 얻어 타야 하다니.","JPN":"しかし、妙な状況だな。マクレディー家の人間がトラックの荷台に乗せてもらわなくてはならないとは。","ENG":"What an ironic situation. A MacCready riding in the back of a truck.","TWN":"不過真是不可思議啊。麥克蕾蒂家族的人居然要搭順風車，而且還是坐在卡車車廂裡。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"불행 중 다행이죠. 히치하이킹에 실패했으면 아직도 황무지를 걷고 있었을 테니까요.","JPN":"不幸中の幸いというべきでしょう。ヒッチハイクに失敗していたら、まだ荒れ地を歩いていたはずですから。","ENG":"Lucky it was not worse. We would be walking across this wasteland if we had failed to hitch a ride.","TWN":"這是不幸中的大幸。搭順風車失敗的話，我們現在應該還在荒郊野外走路呢。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 사장님도 날지 못해서 제 어깨를 빌린 처지 아닌가요? 피차일반인 셈이죠.","JPN":"それに、社長も飛べずに私の肩を借りている身ではないですか。お互い様ですわ。","ENG":"Likewise, you are borrowing my shoulder because you can't fly. So are you not in the same situation as us?","TWN":"還有，老闆也是不能飛，才借用我的肩膀吧？大家處境相同不是嗎。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 이거 정곡을 찔렸군.","JPN":"はは、これは痛いところを突かれたな。","ENG":"Haha. Rubbing salt in my wounds, eh?","TWN":"哈哈，你說這話真是命中要害。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조금은 화를 내시라고요. 발끈한 저만 좀스러운 것 같잖아요.","JPN":"少しは怒ってください。かっとなった私だけ器が小さい人みたいではないですか。","ENG":"I want you to get a little angry. I seem petty if I am the only one fuming.","TWN":"你也可以發火啊。只有我一個人生氣的話，顯得我多小氣。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"루나, 수도원까지는 얼마나 더 가야 하죠?","JPN":"ルナさん、修道院まではあとどれほどかかりますか？","ENG":"Luna, how much farther until we arrive at the monastery?","TWN":"露娜，還要走多久才能到修道院？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"말 걸지 마…. 날지 못하니까 멀미 때문에 죽겠어….","JPN":"話しかけないで……飛べないし、車酔いのせいで死にそうなんだから……","ENG":"Don't talk to me... I'm getting carsick...","TWN":"別跟我說話……因為不能飛，我現在很暈……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"몸이 잿가루가 돼서 날리고 있잖아요! 어서 내려서 바람 좀 쐐요!","JPN":"体が灰になって飛ばされているではないですか！　早く降りて風に当たりなさい！","ENG":"Your body is flaking into ashes! Get out and get some fresh air!","TWN":"你的身體好多灰塵！快點下來呼吸點新鮮空氣吧！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"후아, 이제 좀 살겠다. 생각보다 회복에 힘을 너무 많이 썼나 봐.","JPN":"ふわ～生き返る。思ったより回復に力を使い過ぎてたみたい。","ENG":"Huah! That's so much better. Maybe I used up too much of my power recovering...","TWN":"呼，總算活過來了。看來想要恢復狀態，比我預期得更耗體力。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그 괴물 녀석, 또 나타나면 셰나한테 혼내 달라고 해야지! 다음에 나타나기만 해!","JPN":"あの怪物め、また現れたらシェナにとっちめてもらう！　覚えてろよ！","ENG":"That monster... I'm going to tell Shena to rip it a new one the next time I see it!","TWN":"如果那個怪物再出現的話，我一定要讓世娜好好教訓它！看它敢不敢再出現！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"셰나란 분은 굉장히 힘이 세신가 봐요.","JPN":"シェナという方はとてもお強い方のようですね。","ENG":"This Shena person must be really strong.","TWN":"看來那個叫世娜的人很厲害。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그럼. 평소엔 웃고 다녀도 화나면 얼마나 무서운데.","JPN":"もちろん。普段は笑っていても怒るとものすごく怖いんだから。","ENG":"Yup! She may always smile, but if you irritate her, she'll be the scariest person you'll ever meet.","TWN":"那當然。平時笑的時候就很嚇人，生氣的話會更加可怕。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"그 녀석, 셰나 앞에 서면 꼼짝도 못 할 걸? 퓩퓩 찔려서 걸레짝이나 되라지!","JPN":"あいつ、シェナの前では動けもしないよ！　ブスブス刺されてボロボロになっちゃえ！","ENG":"I bet it won't even be a match against Shena. She'll stab it and turn it to rags in mere seconds!","TWN":"那傢伙，站在世娜面前估計動都動不了？肯定會被撕爛！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대체 그 괴물에게 얼마나 심하게 당했는데 그래요?","JPN":"いったいあの怪物にどれほど酷くやられたのですか？","ENG":"How badly were you injured by it anyway?","TWN":"你到底和那個怪物有什麼深仇大恨？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"허리가 동강나 버렸어.","JPN":"体が真っ二つになったんだ。","ENG":"It cut me in half by the waist.","TWN":"我被它劈成兩半。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"허리가요? 그러고도 살아 있다고요?","JPN":"体がですか？　それでも生きていられるんですの？","ENG":"The waist?! And you are still alive?!","TWN":"劈成兩半？那你為什麼還活著？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"흐흥. 어때, 놀랐냐? 괜히 오래된 그림자가 아니라구.","JPN":"ふふ～ん。どう、驚いた？　シャドウとして伊達に長く生きてないっての。","ENG":"Hehe. Surprised? That's nothing for a ancient Shadow like me.","TWN":"呵呵，怎麼樣，嚇到了？作為古老的暗影，我可不是白活的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 놀랐습니다. 단세포 동물도 그림자가 될 수 있었군요.","JPN":"はい。驚きました。単細胞生物もシャドウになれるのですね。","ENG":"Yes. I am surprised to learn that even someone like you can even become a Shadow.","TWN":"是啊，嚇到我了。原來單細胞生物，也能成為暗影啊。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"누구더러 단세포래? 너 진짜……","JPN":"誰が単細胞だよ！　あんたね……","ENG":"What do you mean \\"someone like me\\"?! Sheesh–","TWN":"你說誰單細胞呢？真是的……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"…잠깐 휴전. 밥부터 먹자.","JPN":"……ちょっと休戦。まず食事をしよう。","ENG":"W-wait. I call truce. I need to eat first","TWN":"……暫時休戰，先去吃飯吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"난 햄버거! 싱싱한 토마토랑 아삭아삭한 양상추, 거기에 두툼한 패티까지~","JPN":"アタシはハンバーガー！　新鮮なトマトにシャキシャキのレタス、それに分厚いパテをのせて～","ENG":"I want a burger! With some fresh tomatoes and crunchy lettuce, and a juicy patty on top!","TWN":"我要吃漢堡！新鮮的番茄，清脆的生菜，再加上厚厚的肉排～"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"크큭, 상상만 해도 입에 침이 고이는데~","JPN":"くくっ、想像しただけでヨダレが出るよ～","ENG":"Ooh... My mouth is already watering!","TWN":"咳咳，光是想想口水就要流下來了～"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"죄송해요, 루나님. 몸만 겨우 빠져나와서 외부인들이 쓰는 돈은 못 챙겨 왔어요.","JPN":"申し訳ありません、ルナ様。体だけどうにか脱出してきたので、領地外の人が使うお金は持っていないのです。","ENG":"I'm sorry, Ms. Luna, but I couldn't bring any outlander money with me because I barely made it out.","TWN":"對不起，露娜。因為好不容易才逃出來的，所以我沒帶外地人用的錢。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"주머니가 넉넉했으면 히치하이킹도 안 했죠. 햄버거는 포기하세요, 루나.","JPN":"懐が暖かかったらヒッチハイクもしていませんわ。ハンバーガーは諦めてください、ルナさん。","ENG":"If we had money, we would not have resorted to hitchhiking in the first place. Give up on eating a hamburger, Luna.","TWN":"如果口袋裡有錢，我們也不用搭別人的順風車。漢堡就不要想了，露娜。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭐? 그럼 나더러 계속 쫄쫄 굶고 다니라고?","JPN":"はあ？　じゃあアタシにずっと飢えてろって？","ENG":"What?! Are you telling me that I should starve to death?!","TWN":"什麼？那你是要我一直餓肚子嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"싫어 싫어! 햄버거 하나 못 사 주는 부학회장은 바보 멍텅구리!","JPN":"やだやだ！　ハンバーガーひとつも買ってくれないなんて、副学会長のバカ！","ENG":"No way! You silly Vice President! Buy me a burger!","TWN":"討厭！連個漢堡都買不起的副學會長是大笨蛋！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으윽…. 성가셔….","JPN":"ううっ……面倒くさいわ……","ENG":"Ugh... You are a handful...","TWN":"呃額……真麻煩……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님은 바보 멍텅구리 아니에요! 얼마나 좋은 분이신데요!","JPN":"副学会長様はバカではありません！　本当に優しい方ですよ！","ENG":"Don't say that she's silly! She's such a kind, gentle being!","TWN":"副學會長不是大笨蛋！她是個好人！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"흥이네요, 메~롱!","JPN":"ふん、べ～っだ！","ENG":"Hmph! Bleh!","TWN":"哼，ㄌㄩㄝ ～！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"우으으……. 정말 아닌데……!","JPN":"ううう……本当なのに……！","ENG":"Ngh... I'm being serious...!","TWN":"唔呃呃……真的不是……！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후우……. 말릴 힘도 없으니 두 분 다 그만해 주세요. 저도 배가 고프긴 마찬가지입니다.","JPN":"ふう……止める元気もありませんから、二人ともそれくらいにしてください。私も空腹なのは同じなのです。","ENG":"*Sigh...* Will you two please knock it off? We are all hungry.","TWN":"呼……我連勸架的力氣都沒有，你們兩個都別再說了。我也一樣很餓。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래도 배가 든든해야 만약의 상황에 대처할 수 있지 않겠나?","JPN":"でも、しっかり食べておかないと万が一の事態に備えられないぞ？","ENG":"But won't having a full stomach help you deal with unexpected situations?","TWN":"可我們需要吃飽飯，才能應付突發情況不是嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혹여 소식을 들은 프리드웬 친구들이 추적에 나설 수도 있으니 말이야.","JPN":"知らせを聞いたプリドウェンの者が追跡を始めることもあるだろうしな。","ENG":"For instance, Prydwen guys might've got word of your whereabouts and are tracking you down as we speak.","TWN":"普利多溫的人聽到消息後，也有可能追過來。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇죠. 리벳도 에델도 없이 저 혼자 기관 사람들에게서 벗어나긴…. 확실히 힘들겠네요.","JPN":"そうですわね。リベットもエデルもない今、私一人で機関の人たちから逃れるのは……確かに難しそうです。","ENG":"Right. Without Edel or Rivet... I cannot possibly get away from the Institution...","TWN":"是啊。里維和艾瑟兒也不在，光靠我自己，確實很難甩掉機關的人……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"위, 위험할 때는 제가 지켜 드릴게요. 마지막까지 꼭 부학회장님을 모실 테니까요.","JPN":"あ、危ない時には私がお守りします。最後まで必ず副学会長様に仕えますから。","ENG":"I-I'll protect you, ma'am. I won't leave you until the very end.","TWN":"遇…遇到危險時我會保護你的。我一定會陪伴副學會長到最後。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇게 말해 주는 것만으로도 고마워요, 실키. 기운이 나네요.","JPN":"そう言ってくれるだけでもありがたいですわ、シルキー。元気が出ました。","ENG":"Thank you for saying that even if you do not mean it, Sylkie. I feel a little better.","TWN":"你能這麼說，我就已經很感激了，思琪。我打起精神了。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"우선 주유소 주인에게 식량이 있는지 물어 보죠.","JPN":"まずはガソリンスタンドのオーナーに食糧があるか聞いてみましょう。","ENG":"First of all, let us go ask the gas station owner if they have anything to eat.","TWN":"先問問加油站的老闆有沒有吃的東西吧。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"돈 대신 제 장신구로 거래할 수 있을 거예요. 장식은 수수해도 어엿한 진품이니까요.","JPN":"お金の代わりに私のアクセサリーで取引できるでしょう。装飾は控えめですがちゃんとした本物ですから。","ENG":"I will exchange my accessories instead of money. They might not look expensive, but they are worth enough.","TWN":"沒有錢，可以用我的飾品交換。飾品雖然很樸素，不過是珍貴的物品喔。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"만세!","JPN":"バンザーイ！","ENG":"Yay!","TWN":"萬歲！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……방금까지 다 죽어가는 것처럼 굴더니 기운이 넘치네.","JPN":"……さっきまでは死にそうな様子でしたのに、元気いっぱいね。","ENG":"...She acted as if she were dying, but now she is alive and well.","TWN":"……剛才還好像一副要死掉的樣子，現在來精神了呢。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"정말요. 꼭 말 안 듣는 개구쟁이 동생이 생긴 것 같아요.","JPN":"本当ですね。まるで言うことを聞かないやんちゃな妹ができたような気分です。","ENG":"I know. It's like I now have a mischievous little sister.","TWN":"真的呢。就好像有了一個不聽話的調皮妹妹。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 내 주위에는 저런 괴짜들만 꼬이는지……","JPN":"どうして私の周りにはああいった変わり者ばかり集まるのかしら……","ENG":"Why do all the weird ones gather around me...?","TWN":"為什麼我的身邊總是只有這種怪人呢……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"언니들도 저를 키울 때 이런 기분이었겠죠….","JPN":"お姉さんたちも私を育てる時にはこんな気持ちだったんでしょうね……","ENG":"I bet my older sisters felt like this when they looked after me.","TWN":"姊姊們養育我的時候，應該就是這種心情吧……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"휴우……","JPN":"ふう……","ENG":"*Sigh...*","TWN":"哀……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하우……","JPN":"はう……","ENG":"*Sigh*","TWN":"哈……"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"매번 괴짜만 꼬이는 것 같으면 본인 문제가 아닐지 돌아봐야 하지 않겠나?","JPN":"毎回変わり者ばかりが集まるのなら、本人の問題ではないか振り返ってみる必要があるんではないかな？","ENG":"Maybe it's not them, but you who is the problem?","TWN":"如果身邊總是有怪人的話，那你應該反省下是不是自己的問題吧？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"크흠. 조용히 하세요.","JPN":"コホン。黙ってください。","ENG":"Ahem...! Quiet.","TWN":"咳咳，你閉嘴。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"와아, 외부인들은 정말 이런 동굴 같은 곳에서 사네요. 실제로는 처음 봤어요.","JPN":"わあ、領地外の人は本当にこんな洞窟みたいなところに住んでいるのですね。実際に見るのは初めてです。","ENG":"Wow...! Outlanders really do live in caves like this. It's my first time seeing one in person.","TWN":"哇啊，外地人真的住在這種洞窟一樣的地方啊。我還是第一次看到實物。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"에이, 이게 뭐야. 가게가 아니라 폐가잖아.","JPN":"ええ、何これ。店じゃなくて廃屋じゃん。","ENG":"Eww, seriously? This isn't a shop, it's a ruin.","TWN":"哎唷，什麼嘛，這裡不是店家，而是個廢屋啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러게요. 햄버거는 기대를 접어야겠네요.","JPN":"そうですね。ハンバーガーは諦めた方が良さそうですわ。","ENG":"I suppose so. I assume there are no hamburgers here.","TWN":"是啊，那你對漢堡的期待就泡湯了呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"어째 잘됐다는 투로 말한다?","JPN":"なんだか、しめたって口調だね？","ENG":"Why do you sound relieved?","TWN":"你怎麼一副暗爽的口氣？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 되는 편지 한 장 가지고 절 가둬 둔 대가라고 생각하세요.","JPN":"お話にもならないような手紙一枚で私を閉じ込めた罰だと思いなさい。","ENG":"Think of it as payback for locking me up in a room because a letter told you to.","TWN":"就當是你拿著一封完全說不通的信，把我關起來的代價吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님, 여기 좀 보세요.","JPN":"副学会長様、これを見てください。","ENG":"Vice President, look over here.","TWN":"副學會長，你看這裡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"유리병 안에 신기한 게 들어 있어요. 알록달록해서 무척 예뻐요.","JPN":"ガラス瓶の中に不思議なものが入っていますよ。色とりどりでとても綺麗です。","ENG":"There's something strange inside this glass jar. They're all colorful and pretty.","TWN":"玻璃瓶裡有神奇的東西。五顏六色的，很漂亮。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이건 사탕이에요. 제가 어릴 때 먹은 제품인데 아직도 파네요.","JPN":"これはキャンディーです。私が小さい頃に食べていた製品ですが、まだ売っているのですね。","ENG":"Those are called candies. It is the exact one I used to eat as a kid. I am surprised they still sell them.","TWN":"這是糖果。我小時候吃過的東西，沒想到現在還在賣。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"사탕이요?","JPN":"キャンディー？","ENG":"Candies?","TWN":"糖果？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……아.","JPN":"……あ。","ENG":"Oh...","TWN":"……啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 입에 물고 있으면 계속 달콤한 맛이 나는 과자입니다.","JPN":"はい。口に含んでいるとずっと甘い味がするお菓子ですわ。","ENG":"Yes. You put one in your mouth and let its sweetness melt.","TWN":"是的，含在嘴裡，就一直有甜味。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"정말요? 제가 영지 바깥을 잘 모른다고 놀리시는 거 아니죠?","JPN":"本当ですか？　私が領地の外をよく知らないからといって、からかってるのではありませんよね？","ENG":"Really? You're not making fun of me because it's my first time being out here, are you?","TWN":"真的嗎？你不會因為我不知道領地外面的事，故意捉弄我吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양 말이 맞다네. 그 대신 먹고 나면 이빨을 꼭 닦아야 하지.","JPN":"マクレディー君の話は本当さ。その代わりに食べた後には必ず歯を磨かないといけない。","ENG":"Regina is telling the truth. But make sure to brush your teeth after having one.","TWN":"麥克蕾蒂說的沒錯。是可以吃的東西，不過吃完之後，必須好好刷牙。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"깜빡하고 자면 아주 무서운 일이 벌어질 거야….","JPN":"うっかり眠ってしまうと、とても恐ろしいことになるぞ……","ENG":"Something very scary will happen if you forget and just go to bed...","TWN":"忘記刷牙就睡覺的話，會發生很可怕的事……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저주가 걸려 있어서 그렇군요! 그럴 줄 알았어요!","JPN":"呪いがかけられているからですね！　そうだと思いました！","ENG":"So it's cursed! I knew it!","TWN":"原來它上面有詛咒啊！我就知道會是這樣！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님. 성실한 아이에게 오해할 만한 소리 하지 마세요.","JPN":"社長。真面目な子が誤解するようなことを言わないでください。","ENG":"Boss. Please do not say things that she might misunderstand.","TWN":"老闆，請不要說一些會讓誠實的孩子產生誤會的話。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하나쯤은 사 줘도 좋겠는데 포장지에 적힌 년도가……","JPN":"一つくらいは買ってあげてもいいのですが、包み紙に刻印されている年度が……","ENG":"I guess I could buy her one. I wonder what the expiration date is...","TWN":"我可以給你買一個，包裝紙上寫的年份是……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으음. 안 되겠네요. 50년은 더 지났어요.","JPN":"うーん、駄目ですわね。50年は過ぎています。","ENG":"Hmm... No good. It expired 50 years ago.","TWN":"呃嗯，不行呢，已經過期50年了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"앗, 전 괜찮아요, 부학회장님. 정말 아무렇지도 않아요.","JPN":"あっ、お気になさらないでください、副学会長様。本当になんてことありません。","ENG":"Oh, it's okay, ma'am. I don't mind.","TWN":"啊，我沒關係，副學會長。我不會在意的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 안 괜찮아요. 영지의 주민들은 살면서 사탕 한 알 제대로 맛보지 못한다는 거니까.","JPN":"私が気にしますわ。領地の住民が生涯にキャンディーのひとつも味わえないことになるのですから。","ENG":"I do. It is my fault the residents at the estate do not know what candy tastes like.","TWN":"可我在意。作為領地的居民，有生以來居然連一顆糖果都沒吃過。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"영지 바깥에는 사탕 말고도 맛있는 과자가 많아요.","JPN":"領地の外にはキャンディー以外にもおいしいお菓子がたくさんあります。","ENG":"Out of the estate, there are more delicious snacks other than just candy.","TWN":"領地外面除了糖果，還有很多好吃的餅乾。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"간병의 대가로 꼭 잔뜩 대접해 줄게요.","JPN":"看病の対価として山ほどご馳走すると約束しますわ。","ENG":"As my caregiver, I will make sure you try them.","TWN":"我一定給你買一大堆，就當是你照顧我的謝禮。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저런. 하루 종일 이빨만 닦아야겠군, 실키 양.","JPN":"おっと。一日中歯磨きをしないといけないな、シルキー君。","ENG":"Oh dear. You'll be brushing your teeth all day long, Sylkie.","TWN":"哎呀，那你一整天都得刷牙呢，思琪。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그, 그럴 수가…….","JPN":"そ、そんな……","ENG":"B-but I don't want to do that...","TWN":"怎…怎麼可能……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"한 번만 더 놀리면 새장에 가둬 놓고 다니겠습니다.","JPN":"もう一度からかうようなら鳥かごに入れますわよ。","ENG":"You tease her one more time and I will put you in a cage.","TWN":"你要是再捉弄她，我就把你關進鳥籠裡。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠. 자제하지.","JPN":"コホン。慎もう。","ENG":"Ahem. Duly noted.","TWN":"咳咳，我儘量注意。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으으. 이것도 저것도 다 유통기한이 지난 것뿐이야.","JPN":"うう。あれもこれもみんな賞味期限が切れてる。","ENG":"Ngh... Everything here's expired.","TWN":"嗚嗚，好多東西，可全都過期了呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"햄버거 하나 마음대로 못 먹다니…… 이런 법이 어딨냐구…….","JPN":"ハンバーガーもろくに食べられないなんて……こんなのないよ……","ENG":"I can't even have a lousy burger...? What kind of cruel joke is that...?","TWN":"連個漢堡都不能隨便吃……怎麼會這樣……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"OLD_NPC_ESPR2_NULL","text":{"KOREA":"뭐야, 왜 이리 시끄러워…….","JPN":"お前たち何だ、騒がしくして……","ENG":"Huh? What's going on out there...?","TWN":"怎麼回事，為什麼這麼吵……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_DOOR_SLIDE"},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아. 죄송합니다. 너무 어질러져 있어서 영업을 안 하시는 줄 알았어요.","JPN":"あ。申し訳ございません。あまりにも散らかっていたので、営業をされていないのかと思いました。","ENG":"Oh, my apologies. It was so dirty that we assumed this shop was abandoned.","TWN":"啊，對不起，這裡太亂了，我們還以為不營業了呢。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLD_NPC_ESPR2_NULL","text":{"KOREA":"다 너희 같이 버르장머리 없는 어린 것들이 들쑤시고 다닌 탓이지. 카악, 퉤!","JPN":"お前たちのような行儀の悪い若者が引っ搔き回すせいだ。カーッ、ペッ！","ENG":"It's messy because rascals like you keep pokin' around! Khaaack, ptooey!","TWN":"都是因為你們這種沒規矩的小孩子亂翻的緣故，討厭呸！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OLD_NPC_ESPR2_NULL","text":{"KOREA":"말해. 내 가게에는 왜 들어왔어?","JPN":"言え。俺の店に何で入ってきた？","ENG":"Tell me, what're y'all doin' in my shop?","TWN":"說吧，你們進我的店裡想幹什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"으. 저 인간은 왜 바닥에 가래를 뱉어. 더럽게.","JPN":"うう。あの人間、なんで床に痰を吐くんだよ。汚いなあ。","ENG":"Eww, gross... Why'd that guy hock a loogie?","TWN":"呃，那個人為什麼要往地板上吐痰啊，髒死了。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저희는 발렌티누스 수도원이란 곳으로 가는 중입니다.","JPN":"私たちはバレンチヌス修道院というところに向かう途中なのです。","ENG":"We are on our way to the Valentinus Monastery.","TWN":"我們要去一個叫聖華倫修道院的地方。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OLD_NPC_ESPR2_NULL","text":{"KOREA":"수도원? 제 발로 그 곳에 간다고?","JPN":"修道院？　自分の足でそこに行くだと？","ENG":"The monastery? You're tellin' me you headed up there?","TWN":"修道院？主動去那個地方？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 그런데 급하게 오느라 식사를 거르고 말았어요.","JPN":"はい。ところで急いでいたので食事ができませんでした。","ENG":"Yes. But we have not eaten anything on our journey over there.","TWN":"是的，但是因為來得太急，所以沒吃飯。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OLD_NPC_ESPR2_NULL","text":{"KOREA":"그렇단 말이지. 재밌겠구만. 아주 재밌겠어.","JPN":"そうか。面白い。まったく面白いぞ。","ENG":"Is that so, eh? Interestin' folks y'all are.","TWN":"這樣啊。有意思，有意思啊。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_NPC_ESPR2_NULL","text":{"KOREA":"구석 찬장에 통조림이 있다. 가져가.","JPN":"奥の棚に缶詰がある。持っていけ。","ENG":"There's some canned food in the corner cupboard. Take 'em.","TWN":"角落的櫃子裡有罐頭，你們拿走吧。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"감사합니다. 그렇다면 계산은 이 반지로……","JPN":"ありがとうございます。ではお会計はこの指輪で……","ENG":"Thank you. I would also like to pay with this ring...","TWN":"謝謝你，那就用這個戒指結帳吧……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"OLD_NPC_ESPR2_NULL","text":{"KOREA":"크흐흐, 계산이 왜 필요해. 너희는 결국 값을 치를 텐데.","JPN":"くふふ、金など必要ない。お前らは結局はその対価を払うことになるんだからな。","ENG":"Kehehe... I don't need your money. You'll be paying for it later.","TWN":"呵呵呵，不需要結帳，因為你們終究會付出代價。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 통조림들은 먹어도 탈이 없겠어요. 언동과 다르게 좋은 분이네요.","JPN":"この缶詰は食べても平気そうですわね。言動とは違っていい方ですわ。","ENG":"I hope we do not get sick eating this canned food... But he was kinder than I thought he would be.","TWN":"這些罐頭吃下去應該沒問題吧。雖然一副凶神惡煞的，但他是個好人。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"방금 저 더러운 늙은이가 의미심장한 말 하는 거 못 들었어? 뭘 아무렇지 않게 넘어가?","JPN":"さっきあの汚い老人の意味深な言葉、聞こえなかった？　疑問に思わないの？","ENG":"Didn't you hear that old guy say some creepy stuff? What do you mean he was nice?!","TWN":"你沒聽到剛才那個髒老頭說的話嗎？那種意味深長的表情，你怎麼能若無其事呢？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네? 수도원에서 돌아올 때 갚으라는 얘기 아니셨어요?","JPN":"え？　修道院から戻ってくる時に払えという意味じゃなかったんですか？","ENG":"Huh? Didn't he mean that we'd paid for it once we got back from the monastery?","TWN":"什麼？不是讓我們從修道院回來的時候，再還錢的意思嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"나이 지긋한 노인 분이세요. 허공에 대고 넋두리를 늘어놔도 이상할 것 없어요.","JPN":"かなりご年配の方ですもの。あさっての方に向かって愚痴をこぼしてもおかしくはありませんわ。","ENG":"He is old and senile. No one would even care if he started grumbling at nothing.","TWN":"一位上了年紀的老人，對著空氣說三道四，也沒什麼奇怪的。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"통조림은 챙겼으니까 이만 가죠. 운전사 분이 기다리시겠어요.","JPN":"缶詰もいただいたことですし、もう行きましょう。運転手さんがお待ちですわ。","ENG":"We got our food, so let us get moving. Our driver is waiting.","TWN":"罐頭已經裝好了，我們走吧。司機還在等我們呢。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"으음, 저걸 대담하다고 해야 할지 무신경하다고 해야 할지 모르겠군.","JPN":"うーむ、大胆というべきか無神経というべきか。","ENG":"Hmm... I don't know if she's bold or indifferent about the whole thing...","TWN":"呃嗯，真不知道該說她是膽子大，還是後知後覺。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아니. 쟤네는 그냥 겁나게 둔감한 거야.","JPN":"ううん。あいつらは単にめちゃくちゃ鈍いだけだと思う。","ENG":"Neither. Those two are utterly clueless.","TWN":"不，她一定是後知後覺才對。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};